@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (_loading)
{
    <div class="alert alert-info">Loading tasks…</div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <BoardStatsBar Tasks="FilteredTasks" AllTasks="_tasks" />

    <BoardSearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3 mt-2">
        @foreach (var col in _columns)
        {
            var tasksInColumn = FilteredTasks.Where(t => t.Status == col).ToList();
            var isFirst = col == _columns[0];
            var isLast = col == _columns[^1];

            <div class="col-md-4">
                <BoardColumn ColumnName="@col"
                             Tasks="tasksInColumn"
                             ShowMoveLeft="!isFirst"
                             ShowMoveRight="!isLast"
                             OnMoveLeft="async id => await MoveTask(id, _columns[Array.IndexOf(_columns, col) - 1])"
                             OnMoveRight="async id => await MoveTask(id, _columns[Array.IndexOf(_columns, col) + 1])"
                             OnAddTask="async args => await AddTask(col, args)" />
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> _tasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _error;

    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(_searchTerm)
            ? _tasks
            : _tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        _searchTerm = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _tasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _tasks[idx] = _tasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(string status, AddTaskArgs args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _tasks.Add(created);
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

@* Summary statistics bar displayed at the top of the board *@

<div class="d-flex flex-wrap gap-3 mb-3">
    <span class="badge bg-primary fs-6">Total: @AllTasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @AllTasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @AllTasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @AllTasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @AllTasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> AllTasks { get; set; } = default!;
}

